				d = ff.Sub(ctrf)
				cv := WavePacket(d.Dim(dim), d.Length(), vwavelength, vwidth, vphase, vamp)
				State.SetAdd(cv, int(f.Z), int(f.Y), int(f.X), int(velI), int(cur))

