				d = ff.Sub(ctrf)
				pv := WavePacket(d.Dim(dim), d.Length(), 0.996*vwavelength, 0.997*vwidth, vphase, vamp)
				State.SetAdd(pv, int(f.Z), int(f.Y), int(f.X), int(velI), int(prv))
